#!/usr/bin/env python
"""
Test to verify that the pre_validate signal is properly defined and dispatched.
This test can be run with: python test_pre_validate.py
"""
import sys
import os

# Add the workspace to the path
sys.path.insert(0, '/workspace')

def test_pre_validate_signal_exists():
    """Test that pre_validate signal can be imported."""
    try:
        from django.db.models.signals import pre_validate
        print("✓ pre_validate signal is importable")
        return True
    except ImportError as e:
        print(f"✗ Failed to import pre_validate: {e}")
        return False


def test_pre_validate_is_model_signal():
    """Test that pre_validate is a ModelSignal instance."""
    try:
        from django.db.models.signals import pre_validate, ModelSignal
        if isinstance(pre_validate, ModelSignal):
            print("✓ pre_validate is a ModelSignal instance")
            return True
        else:
            print(f"✗ pre_validate is not a ModelSignal: {type(pre_validate)}")
            return False
    except Exception as e:
        print(f"✗ Error checking ModelSignal: {e}")
        return False


def test_signal_definition_location():
    """Test that pre_validate is defined in the correct location."""
    try:
        import django.db.models.signals as signals_module
        if hasattr(signals_module, 'pre_validate'):
            print("✓ pre_validate is defined in django.db.models.signals")
            return True
        else:
            print("✗ pre_validate is not defined in django.db.models.signals")
            return False
    except Exception as e:
        print(f"✗ Error checking signal module: {e}")
        return False


def test_base_imports_pre_validate():
    """Test that base.py imports pre_validate."""
    try:
        with open('/workspace/django/db/models/base.py', 'r') as f:
            content = f.read()
            if 'pre_validate' in content:
                if 'from django.db.models.signals import' in content and 'pre_validate' in content:
                    print("✓ base.py imports pre_validate")
                    return True
                else:
                    print("✗ pre_validate is mentioned in base.py but not properly imported")
                    return False
            else:
                print("✗ pre_validate is not mentioned in base.py")
                return False
    except Exception as e:
        print(f"✗ Error checking base.py: {e}")
        return False


def test_signal_dispatch_in_full_clean():
    """Test that pre_validate is dispatched in full_clean."""
    try:
        with open('/workspace/django/db/models/base.py', 'r') as f:
            content = f.read()
            if 'pre_validate.send(' in content:
                print("✓ pre_validate signal is dispatched in full_clean")
                return True
            else:
                print("✗ pre_validate signal dispatch not found in base.py")
                return False
    except Exception as e:
        print(f"✗ Error checking base.py: {e}")
        return False


def test_signal_dispatch_receives_correct_parameters():
    """Test that pre_validate dispatch includes the correct parameters."""
    try:
        with open('/workspace/django/db/models/base.py', 'r') as f:
            content = f.read()
            # Look for the signal dispatch
            if 'pre_validate.send(' in content:
                # Extract the section around the pre_validate.send call
                start_idx = content.find('pre_validate.send(')
                end_idx = content.find(')', start_idx) + 1
                dispatch_call = content[start_idx:end_idx]

                required_params = ['sender=', 'instance=', 'exclude=', 'validate_unique=', 'validate_constraints=']
                missing_params = [p for p in required_params if p not in dispatch_call]

                if not missing_params:
                    print("✓ pre_validate dispatch includes all required parameters")
                    return True
                else:
                    print(f"✗ pre_validate dispatch missing parameters: {missing_params}")
                    return False
            else:
                print("✗ pre_validate.send call not found")
                return False
    except Exception as e:
        print(f"✗ Error checking dispatch parameters: {e}")
        return False


def test_signal_dispatch_timing():
    """Test that pre_validate is dispatched before validation logic."""
    try:
        with open('/workspace/django/db/models/base.py', 'r') as f:
            lines = f.readlines()

            # Find the full_clean method
            full_clean_idx = None
            for i, line in enumerate(lines):
                if 'def full_clean(self' in line:
                    full_clean_idx = i
                    break

            if full_clean_idx is None:
                print("✗ Could not find full_clean method")
                return False

            # Find the pre_validate.send call
            pre_validate_idx = None
            clean_fields_idx = None

            for i in range(full_clean_idx, min(full_clean_idx + 100, len(lines))):
                if 'pre_validate.send(' in lines[i]:
                    pre_validate_idx = i
                if 'self.clean_fields(' in lines[i]:
                    clean_fields_idx = i

            if pre_validate_idx is None:
                print("✗ Could not find pre_validate.send call")
                return False

            if clean_fields_idx is None:
                print("✗ Could not find clean_fields call")
                return False

            if pre_validate_idx < clean_fields_idx:
                print("✓ pre_validate is dispatched before validation logic")
                return True
            else:
                print("✗ pre_validate is dispatched after validation logic (wrong order)")
                return False
    except Exception as e:
        print(f"✗ Error checking dispatch timing: {e}")
        return False


def main():
    """Run all tests."""
    print("Testing pre_validate signal implementation...\n")

    tests = [
        test_pre_validate_signal_exists,
        test_pre_validate_is_model_signal,
        test_signal_definition_location,
        test_base_imports_pre_validate,
        test_signal_dispatch_in_full_clean,
        test_signal_dispatch_receives_correct_parameters,
        test_signal_dispatch_timing,
    ]

    results = []
    for test in tests:
        try:
            result = test()
            results.append(result)
        except Exception as e:
            print(f"✗ Test {test.__name__} failed with exception: {e}")
            results.append(False)

    print(f"\n{'='*60}")
    passed = sum(results)
    total = len(results)
    print(f"Results: {passed}/{total} tests passed")

    if passed == total:
        print("✓ All tests passed!")
        return 0
    else:
        print(f"✗ {total - passed} test(s) failed")
        return 1


if __name__ == '__main__':
    sys.exit(main())

